const items = $input.all();
const nuevosItems = [];

for (const item of items) {
  // Creamos un nuevo objeto con todas las propiedades originales
  // y añadimos el campo 'text' con el valor de 'output'
  const nuevoItem = {
    json: {
      ...item.json,
      text: item.json.output,
      content: item.json.output
    }
  };
  nuevosItems.push(nuevoItem);
}

return nuevosItems;

const items = $input.all();
const nuevosItems = [];

for (const item of items) {
  try {
    let str = item.json.output;

    // Reemplazar escapes Unicode compuestos del estilo \u{1F6E0\uFE0F}
    str = str.replace(/\\u\{([^}]+)\}/g, (match, inner) => {
      const parts = inner.split(/\\u/);
      let result = '';
      for (let part of parts) {
        if (part === '') continue;
        result += String.fromCodePoint(parseInt(part, 16));
      }
      return result;
    });

    // Parsear el JSON principal
    const datosParseados = JSON.parse(str);

    // Verificar si existe la propiedad "output" y si contiene el patrón equipo_asignado: "valor"
    if (datosParseados.output && typeof datosParseados.output === 'string') {
      const match = datosParseados.output.match(/^\s*equipo_asignado:\s*"([^"]*)"\s*$/);
      if (match) {
        // Agregar la nueva propiedad "equipo_asignado" con el valor extraído
        datosParseados.equipo_asignado = match[1];
      }
    }

    // Agregar el objeto enriquecido a la salida
    nuevosItems.push({ json: datosParseados });

  } catch (e) {
    // Si falla, devolver información del error
    nuevosItems.push({
      json: {
        error: e.message,
        original: item.json.output
      }
    });
  }
}

return nuevosItems;

return items.map(item => {
  try {
    const parsed = JSON.parse(item.json.output);
    return { json: parsed };
  } catch (e) {
    return {
      json: {
        success: false,
        error: 'JSON inválido recibido del LLM',
        raw_output: item.json.output
      }
    };
  }
});

// Recorremos cada elemento de entrada
for (const item of $input.all()) {
  // Inicializamos variable para el mensaje extraído
  let mensajeExtraido = null;

  // Verificamos si existe la estructura esperada
  if (item.json.error && item.json.error.message) {
    const mensajeCompleto = item.json.error.message;

    // Buscamos el inicio del JSON (después del código de estado y el espacio)
    // El formato típico: "400 - {\"success\": false, ...}"
    const indiceJson = mensajeCompleto.indexOf('{');
    if (indiceJson !== -1) {
      const posibleJson = mensajeCompleto.substring(indiceJson);
      try {
        // Reemplazar las barras invertidas escapadas para obtener un JSON válido
        const jsonLimpio = posibleJson.replace(/\\"/g, '"');
        const objetoError = JSON.parse(jsonLimpio);
        // Extraemos el campo "error" del JSON (el mensaje para el usuario)
        if (objetoError.error) {
          mensajeExtraido = objetoError.error;
        }
      } catch (e) {
        // Si falla el parseo, podemos dejar el mensaje original o null
        console.error('Error al parsear JSON:', e);
      }
    }
  }

  // Agregamos el campo extraído al item (si se encontró)
  item.json.error_extraido = mensajeExtraido || 'No se pudo extraer el error';
}

// Devolvemos todos los elementos modificados
return $input.all();

const items = $input.all();

if (items.length === 0) {
  throw new Error('No se recibieron elementos');
}

// Función para fusionar objetos dando prioridad a valores no nulos
function mergeNonNulls(target, source) {
  const result = { ...target };
  for (const key in source) {
    // Si el valor en source NO es null/undefined, lo usamos
    if (source[key] !== null && source[key] !== undefined) {
      // Para objetos anidados, fusionar recursivamente
      if (typeof source[key] === 'object' && source[key] !== null && !Array.isArray(source[key])) {
        result[key] = mergeNonNulls(result[key] || {}, source[key]);
      } else {
        result[key] = source[key];
      }
    }
  }
  return result;
}

// Combinar todos los items, priorizando valores no nulos
let combinado = {};
for (const item of items) {
  combinado = mergeNonNulls(combinado, item.json);
}

// Guardar valores críticos que NO deben perderse (por si acaso)
const valoresCriticos = {
  conversation_id: combinado.conversation_id,
  account_id: combinado.account_id,
  session_id: combinado.session_id,
  platform: combinado.platform,
  lead_id: combinado.lead_id,
  cliente_id: combinado.cliente_id
};

// 1. Prioridad: error
if (combinado.error) {
  combinado.text = combinado.error;
  combinado.content = combinado.error;
  combinado.valor = combinado.error;
}
// 2. Cancelación (valor CANCELAR)
else if (combinado.valor === "CANCELAR" || combinado.text === "CANCELAR" || combinado.content === "CANCELAR") {
  const mensajeCancelacion = "Gracias por tu interés. Has cancelado el proceso de agendamiento. Cuando quieras, puedes volver a empezar desde el menú principal. 😊";
  combinado.valor = mensajeCancelacion;
  combinado.text = mensajeCancelacion;
  combinado.content = mensajeCancelacion;
}
// 3. Flujo completado - mantener mensaje original si existe
else if ((combinado.paso_actual === "COMPLETADO" || combinado.completado === true)) {
  // Si ya hay respuesta_para_bot o texto, NO sobrescribir
  if (!combinado.respuesta_para_bot && (!combinado.text || combinado.text === combinado.valor)) {
    const mensajeCompletado = "¡Tus datos han sido registrados! Estamos procesando tu solicitud. Presiona cualquier tecla para continuar. 😊";
    combinado.text = mensajeCompletado;
    combinado.content = mensajeCompletado;
    combinado.valor = mensajeCompletado;
  }
}
// 4. nombre_mostrar
else if (combinado.nombre_mostrar && !combinado.text) {
  combinado.text = combinado.nombre_mostrar;
  combinado.content = combinado.nombre_mostrar;
}

// Asegurar que los valores críticos se mantengan (por si la fusión falló)
combinado.conversation_id = valoresCriticos.conversation_id;
combinado.account_id = valoresCriticos.account_id;
combinado.session_id = valoresCriticos.session_id;
combinado.platform = valoresCriticos.platform;
combinado.lead_id = valoresCriticos.lead_id;
combinado.cliente_id = valoresCriticos.cliente_id;

// Si hay respuesta_para_bot, asegurar que sea el valor principal
if (combinado.respuesta_para_bot && !combinado.error) {
  combinado.valor = combinado.respuesta_para_bot;
  if (!combinado.text || combinado.text === combinado.valor_anterior) {
    combinado.text = combinado.respuesta_para_bot;
    combinado.content = combinado.respuesta_para_bot;
  }
}

return [{ json: combinado }];
